INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-04', 'قتل', 'آخر طلب في مطعم الحسين', 'في ليلة زحمة في مطعم مشهور في الحسين، صاحب المطعم اتلقى طعنة في المخزن الخلفي وهو بيجهّز طلبية خاصة. الباب الخلفي كان مفتوح والكاميرات مكانتش شغالة من بدري. أربع ناس كانوا موجودين في المطعم وقت الحادثة.', 4, 1, 'سيف', 'صاحب المطعم نزل المخزن لوحده بعد ما حد طلب منه طلبية مخصوصة; الكاميرا اللي في الممر الخلفي كانت فاصلة من قبل الحادثة بنص ساعة; باب المخزن الخلفي لقوه مفتوح مع إن المفروض يكون مقفول.', 'واحد من الموجودين اتشاف وهو نازل ناحية المخزن قبل الحادثة بدقايق; صاحب المطعم كان بيهدد حد إنه هيبلّغ عنه بسبب فلوس ناقصة; لقوا موبايل الضحية عليه رسالة متمسحة بس رجعوها واتضح إنها من حد من الموجودين.', 'سكينة من المطبخ مكانتش في مكانها وبعدين رجعت اتمسحت; واحد من الأربعة عنده مفتاح احتياطي للباب الخلفي ومحدش كان يعرف; الطلبية المخصوصة اللي خلّت صاحب المطعم ينزل المخزن ملهاش أي أوردر مسجل في النظام.', 'سيف كان شغال شيف في المطعم وكان بيسرق من الحسابات من زمان. صاحب المطعم اكتشف الموضوع وهدده إنه هيروح البوليس. سيف استنى لحد ما صاحب المطعم نزل المخزن، فصل الكاميرا قبلها، ونزله طعنه وطلع كمّل شغله عادي.', 'منى السيرفر كانت بتاخد تيبس من الزباين وتخبيه من الإدارة; باسم الكاشير كان بيغير في الفواتير عشان يطلع فرق لنفسه; نورا المديرة كانت بتستخدم عربية المطعم في حاجات شخصية ومش عايزة حد يعرف.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
  ((SELECT id FROM cases WHERE case_code = 'M-04' AND player_count = 4), 'سيف', 1, 'الشيف الأساسي في المطعم من ٥ سنين، معروف إنه شاطر في شغله بس عصبي ودايمًا بيتخانق مع صاحب المطعم.', true),
  ((SELECT id FROM cases WHERE case_code = 'M-04' AND player_count = 4), 'منى', 2, 'سيرفر شغالة في المطعم من سنة، بشوشة والزباين بيحبوها. كانت أقرب واحدة للباب الخلفي وقت الحادثة.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-04' AND player_count = 4), 'باسم', 3, 'الكاشير اللي بيقفل الحسابات كل يوم. كان عنده مفتاح المخزن عشان بينزل يعد البضاعة آخر اليوم.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-04' AND player_count = 4), 'نورا', 4, 'مديرة المطعم ومسؤولة عن التشغيل اليومي. عندها صلاحيات الكاميرات وبتقول إنها مكانتش عارفة إنها فاصلة.', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-06', 'قتل', 'الليلة الأخيرة في مكتبة وسط البلد', 'صاحب مكتبة قديمة في شارع محمد فريد اتلقى ميت في المكتبة بعد ما قفلت. كان قاعد على كرسيه ورا المكتب وجنبه فنجان شاي. أربع ناس كانوا آخر الموجودين في المكتبة قبل ما تقفل.', 4, 1, 'عادل', 'صاحب المكتبة شرب شاي في آخر اليوم زي العادة; الفنجان لقوا فيه أثر مادة غريبة; باب المكتبة الخلفي اللي بيطل على السلم كان مفتوح مع إن المفروض يتقفل الساعة ٨.', 'واحد من الموجودين قعد مع صاحب المكتبة لوحده في الآخر; صاحب المكتبة كان بيجمع فلوس كتير كاش ومش بيحطها في البنك; لقوا ورقة في درج المكتب فيها أسامي وأرقام.', 'المادة اللي في الشاي بتتباع في الصيدليات بوصفة بس حد اشتراها من صيدلية قريبة قبل الحادثة بيومين; كاميرا المحل اللي جنب المكتبة صوّرت حد طالع من الباب الخلفي بعد وقت الإغلاق; صاحب المكتبة كان ناوي يغير وصيته ويحرم واحد من اللي حواليه.', 'عادل كان ابن أخو صاحب المكتبة وكان عارف إن خاله ناوي يشيله من الوصية. راح صيدلية في حي تاني واشترى المادة بوصفة مزورة، وحطها في الشاي بتاع خاله وهو بيحضرهوله زي كل يوم.', 'هدى كانت بتيجي المكتبة عشان تصور صفحات من كتب نادرة وتبيعها أونلاين; كمال المحاسب كان بيغطي عجز في الدفاتر من فلوسه; فريدة كانت عايزة تشتري المكتبة بسعر قليل.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
  ((SELECT id FROM cases WHERE case_code = 'M-06' AND player_count = 4), 'عادل', 1, 'ابن أخو صاحب المكتبة، بييجي كل يوم يساعده في الترتيب وبيحضرله الشاي. دايمًا محتاج فلوس. كان آخر واحد شاف خاله حي.', true),
  ((SELECT id FROM cases WHERE case_code = 'M-06' AND player_count = 4), 'هدى', 2, 'باحثة بتيجي المكتبة من زمان وعندها مفتاح الباب الخلفي عشان صاحب المكتبة كان واثق فيها.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-06' AND player_count = 4), 'كمال', 3, 'محاسب بييجي المكتبة مرتين في الأسبوع يراجع الدفاتر. بيقول إنه مشي قبل الإغلاق بس محدش شافه وهو طالع.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-06' AND player_count = 4), 'فريدة', 4, 'سيدة أعمال كانت بتحاول تشتري المكتبة. جت يوم الحادثة وقعدت مع صاحب المكتبة في نقاش طويل بصوت عالي.', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-09', 'قتل', 'موت في عيادة الهرم البيطري', 'دكتور بيطري مشهور في شارع الهرم اتلقى ميت في عيادته الصبح بدري. كان مضروب على راسه بحاجة تقيلة ولقوه على أرض أوضة العمليات. أربع ناس كانوا آخر اللي شافوه إمبارح بالليل.', 4, 1, 'شريف', 'الدكتور فضل في العيادة لوحده بعد ما الكل مشي عشان كان عنده حالة طوارئ; باب العيادة ملقوش عليه أي أثر كسر يعني حد دخل بمفتاح; لقوا تمثال معدني تقيل على مكتب الدكتور وعليه آثار دم.', 'الدكتور كان بيهدد واحد من اللي حواليه إنه هيفضحه قدام النقابة; واحد من الأربعة رجع العيادة بعد ما الكل مشي وكان عنده مفتاح; لقوا على لاب توب الدكتور ملف مشفر فيه معلومات حساسة.', 'المفتاح الاحتياطي لقوه في مكان غلط; كاميرا صيدلية مقابل العيادة صوّرت حد داخل العيادة الساعة ١١ بالليل والدكتور فتحله الباب بنفسه; الملف المشفر فيه إثبات إن حد كان بيزوّر شهادات صحية.', 'شريف كان شريك الدكتور في تجارة جانبية وكان بيزوّر شهادات صحية. الدكتور قرر يوقف ويبلّغ النقابة. شريف راح العيادة بالليل عشان يمسح الملف، الدكتور رفض فشريف ضربه بالتمثال.', 'ياسمين الممرضة كانت بتسرق أدوية بيطرية وتبيعها; أحمد صاحب المحل اللي جنبه كان مديون للدكتور; لمياء مراته كانت عارفة إنه بيخبي فلوس وبيفكروا في الطلاق.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
  ((SELECT id FROM cases WHERE case_code = 'M-09' AND player_count = 4), 'شريف', 1, 'دكتور بيطري وصاحب الدكتور من الكلية. بيشتغلوا في حاجات جانبية مع بعض. كان آخر واحد مشي من العيادة. معروف إنه طماع.', true),
  ((SELECT id FROM cases WHERE case_code = 'M-09' AND player_count = 4), 'ياسمين', 2, 'الممرضة الأساسية في العيادة من ٣ سنين. شاطرة بس الفترة الأخيرة كانت متوترة. بتقول إنها مشيت الساعة ٩.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-09' AND player_count = 4), 'أحمد', 3, 'صاحب محل أكل للحيوانات جنب العيادة. كان بييجي العيادة كتير بس الفترة الأخيرة بيتكلموا بعصبية.', false),
  ((SELECT id FROM cases WHERE case_code = 'M-09' AND player_count = 4), 'لمياء', 4, 'مرات الدكتور، كانت بتعدي عليه في العيادة آخر اليوم. يوم الحادثة قالها يروح لوحده عشان عنده حالة طوارئ.', false);
